import { Component } from '@angular/core';
import { Router } from '@angular/router';
import { ReactiveFormsModule, FormGroup, FormControl, Validators } from '@angular/forms';
import { MatCardModule } from '@angular/material/card';
import { MatFormFieldModule } from '@angular/material/form-field';
import { MatInputModule } from '@angular/material/input';
import { MatButtonModule } from '@angular/material/button';
import { MatProgressBarModule } from '@angular/material/progress-bar';
import { FirebaseService } from '../../services/firebase.service';
import { NotificationService } from '../../services/notification.service';

@Component({
  selector: 'app-login',
  standalone: true,
  imports: [
    ReactiveFormsModule,
    MatCardModule,
    MatFormFieldModule,
    MatInputModule,
    MatButtonModule,
    MatProgressBarModule,
  ],
  templateUrl: './login.html',
  styleUrl: './login.css',
})
export class LoginComponent {
  form = new FormGroup({
    email: new FormControl('', [Validators.required, Validators.email]),
    password: new FormControl('', [Validators.required, Validators.minLength(6)]),
  });

  isSignup = false;
  loading = false;

  constructor(
    private fb: FirebaseService,
    private router: Router,
    private notify: NotificationService,
  ) {}

  async submit(): Promise<void> {
    if (this.form.invalid) {
      this.notify.show('Compila tutti i campi', 'error');
      return;
    }

    const email = this.form.value.email!;
    const password = this.form.value.password!;
    this.loading = true;

    try {
      if (this.isSignup) {
        await this.fb.signup(email, password);
        this.notify.show('Account creato con successo!');
      } else {
        await this.fb.login(email, password);
        this.notify.show('Accesso effettuato!');
      }
      this.router.navigate(['/']);
    } catch (err: unknown) {
      const code = (err as { code?: string }).code ?? '';
      this.notify.show(this.mapError(code), 'error');
    } finally {
      this.loading = false;
    }
  }

  toggleMode(): void {
    this.isSignup = !this.isSignup;
  }

  private mapError(code: string): string {
    switch (code) {
      case 'auth/user-not-found': return 'Utente non trovato';
      case 'auth/wrong-password':
      case 'auth/invalid-credential': return 'Password errata';
      case 'auth/email-already-in-use': return 'Email già in uso';
      case 'auth/weak-password': return 'Password troppo debole (minimo 6 caratteri)';
      case 'auth/invalid-email': return 'Email non valida';
      default: return 'Errore di autenticazione';
    }
  }
}
